{"code": "import json

# Load data from files
civic_file = open('file_storage/functions.query_db:9.json', 'r')
civic_data = json.load(civic_file)
civic_file.close()

funding_file = open('file_storage/functions.query_db:32.json', 'r')
funding_data = json.load(funding_file)
funding_file.close()

# Get funding project names
funding_names = set()
for item in funding_data:
    funding_names.add(item['Project_Name'])

# Extract design projects
design_projects = []
for doc in civic_data:
    text = doc.get('text', '')

    # Find design section
    design_marker = 'Capital Improvement Projects (Design)'
    start = text.find(design_marker)
    if start == -1:
        continue

    # Find end of design section
    construction_marker = 'Capital Improvement Projects (Construction)'
    end = text.find(construction_marker, start)
    if end == -1:
        end = len(text)

    section = text[start:end]
    lines = section.split('\n')

    # Look for project names
    for i in range(len(lines)):
        line = lines[i].strip()
        if len(line) > 5 and not line.isupper():
            bad_words = ['Updates', 'Schedule', 'Advertise', 'Construction', 'Page', 'Agenda']
            has_bad = any(bad in line for bad in bad_words)
            if not has_bad and not line.startswith('('):
                # Check if followed by Updates
                if i+1 < len(lines) and 'Updates:' in lines[i+1]:
                    design_projects.append(line)

# Remove duplicates
unique_projects = []
seen = set()
for proj in design_projects:
    if proj not in seen:
        unique_projects.append(proj)
        seen.add(proj)

# Match with funding
matched = []
for design in unique_projects:
    for funded in funding_names:
        if design in funded or funded in design:
            matched.append(design)
            break

print('__RESULT__:')
result = {'count': len(matched), 'projects': matched[:10]}
print(json.dumps(result))"}

